import{_ as s,m as a,k as n,ah as o,q as e}from"./chunks/framework.BgQAHmMj.js";const c="/docs/images/core-concepts/section-page-relation-en-light.svg",i="/docs/images/core-concepts/section-page-relation-en-dark.svg",r="/docs/images/core-concepts/singleton-vs-collection-en-light.svg",l="/docs/images/core-concepts/singleton-vs-collection-en-dark.svg",k=JSON.parse('{"title":"Core concepts","description":"","frontmatter":{"layout":"doc"},"headers":[],"relativePath":"developers/getting-started/core-concepts.md","filePath":"src/en/developers/getting-started/core-concepts.md"}'),d={name:"developers/getting-started/core-concepts.md"},p=c+"#light-only",h=i+"#dark-only",m=r+"#light-only",g=l+"#dark-only";function u(_,t,f,b,v,C){return n(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="core-concepts" tabindex="-1">Core concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core concepts&quot;">​</a></h1><h2 id="sections" tabindex="-1">Sections <a class="header-anchor" href="#sections" aria-label="Permalink to &quot;Sections&quot;">​</a></h2><p>The basic building block of Creopse is the section, which can be defined as a contextualized and localized content block. Every section has a data structure for organizing its content and parameters for adapting its rendering.</p><h2 id="pages" tabindex="-1">Pages <a class="header-anchor" href="#pages" aria-label="Permalink to &quot;Pages&quot;">​</a></h2><p>Pages in Creopse are stacks of sections whose position and content can be modified. Each page can contain as many sections as needed, and the content of each section is bound to the page it sits on. The same section can therefore be used across multiple pages with different content, or appear multiple times on the same page. It is also possible to bind a section&#39;s content to its content on another page.</p>',5),e("p",null,[e("img",{src:p,alt:"Section / Page relationship"}),e("img",{src:h,alt:"Section / Page relationship"})],-1),o('<h2 id="content-models" tabindex="-1">Content models <a class="header-anchor" href="#content-models" aria-label="Permalink to &quot;Content models&quot;">​</a></h2><p>Content models are data models used to retrieve content tied to the platform&#39;s business context, which can be used throughout the application — for example, services, articles, products, etc. They are accessible from any section on any page.</p><h2 id="data-structures" tabindex="-1">Data structures <a class="header-anchor" href="#data-structures" aria-label="Permalink to &quot;Data structures&quot;">​</a></h2><p>Data structures are descriptions of the shape of the data that makes up the content of various elements such as sections and content models. They allow Creopse to generate the necessary fields for collecting content data in the administration interface.</p><p>Two types of components are distinguished in data structures:</p><ul><li><strong>Singletons</strong>:</li></ul><p>Components used to retrieve simple content data, such as a title, an image, a text, etc.</p><ul><li><strong>Collections</strong>:</li></ul><p>Components used to retrieve complex and repetitive content data, such as a list of team members, a list of customer testimonials, etc.</p>',9),e("p",null,[e("img",{src:m,alt:"Singleton vs Collection"}),e("img",{src:g,alt:"Singleton vs Collection"})],-1)])])}const P=s(d,[["render",u]]);export{k as __pageData,P as default};
